use portfolio_manager_lib::core::create_specta_builder;
use specta_typescript::{BigIntExportBehavior, Typescript};

fn main() {
    // Create tauri-specta builder for type-safe bindings
    let builder = create_specta_builder();

    // Export TypeScript bindings to src/bindings.ts
    // BigIntExportBehavior::Number maps i64 to `number` in TypeScript (safe within Number.MAX_SAFE_INTEGER)
    let ts_config = Typescript::default()
        .bigint(BigIntExportBehavior::Number)
        .header(
            "// @ts-nocheck\n/* eslint-disable */\n// Generated by Specta - do not edit manually\n",
        );
    builder
        .export(ts_config, "../src/bindings.ts")
        .expect("Failed to export typescript bindings");

    println!("Bindings generated successfully!");
}
